            Assert.Empty(model);
        }

        [Fact]
        public void About_GroupsStudentsByEnrollmentDate()
        {
            // Arrange
            _context.Students.AddRange(
                new Student { LastName = "A", FirstMidName = "B", EnrollmentDate = new DateTime(2020, 9, 1) },
                new Student { LastName = "C", FirstMidName = "D", EnrollmentDate = new DateTime(2020, 9, 1) },
                new Student { LastName = "E", FirstMidName = "F", EnrollmentDate = new DateTime(2020, 9, 1) }
            );
            _context.SaveChanges();

            // Act
            var result = _controller.About();

            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsAssignableFrom<List<EnrollmentDateGroup>>(viewResult.Model);
            Assert.Single(model);
            Assert.Equal(3, model[0].StudentCount);
