            Assert.Equal("You don't have permission to access this resource.", _controller.ViewBag.Message);
        }
    }
}

using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Tests.Helpers;
using Microsoft.AspNetCore.Mvc;

namespace ContosoUniversity.Tests.Controllers
{
    public class StudentsControllerTests : IDisposable
    {
        private readonly SchoolContext _context;
        private readonly StudentsController _controller;

        public StudentsControllerTests()
        {
            TestHelper.DrainNotificationQueue();
            _context = TestHelper.CreateInMemoryContext();
            _controller = new StudentsController(_context);
        }

        public void Dispose()
        {
            _controller.Dispose();
            _context.Dispose();
            TestHelper.DrainNotificationQueue();
        }

        #region Index

        [Fact]
        public void Index_DefaultSort_OrdersByLastNameAscending()
        {
            // Arrange
            _context.Students.AddRange(
                new Student { LastName = "Zeta", FirstMidName = "A", EnrollmentDate = DateTime.Today },
                new Student { LastName = "Alpha", FirstMidName = "B", EnrollmentDate = DateTime.Today },
                new Student { LastName = "Mid", FirstMidName = "C", EnrollmentDate = DateTime.Today }
            );
            _context.SaveChanges();

            // Act
            var result = _controller.Index(null, null, null, null);

            // Assert
            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsAssignableFrom<PaginatedList<Student>>(viewResult.Model);
            Assert.Equal("Alpha", model[0].LastName);
            Assert.Equal("Mid", model[1].LastName);
            Assert.Equal("Zeta", model[2].LastName);
        }

        [Fact]
        public void Index_NameDescSort_OrdersByLastNameDescending()
        {
            _context.Students.AddRange(
                new Student { LastName = "Alpha", FirstMidName = "A", EnrollmentDate = DateTime.Today },
                new Student { LastName = "Zeta", FirstMidName = "B", EnrollmentDate = DateTime.Today }
            );
            _context.SaveChanges();

            var result = _controller.Index("name_desc", null, null, null);

            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsAssignableFrom<PaginatedList<Student>>(viewResult.Model);
            Assert.Equal("Zeta", model[0].LastName);
            Assert.Equal("Alpha", model[1].LastName);
        }

        [Fact]
        public void Index_DateSort_OrdersByEnrollmentDateAscending()
        {
            _context.Students.AddRange(
                new Student { LastName = "B", FirstMidName = "B", EnrollmentDate = new DateTime(2022, 1, 1) },
                new Student { LastName = "A", FirstMidName = "A", EnrollmentDate = new DateTime(2020, 1, 1) }
            );
            _context.SaveChanges();

            var result = _controller.Index("Date", null, null, null);

            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsAssignableFrom<PaginatedList<Student>>(viewResult.Model);
            Assert.Equal(new DateTime(2020, 1, 1), model[0].EnrollmentDate);
            Assert.Equal(new DateTime(2022, 1, 1), model[1].EnrollmentDate);
        }

        [Fact]
        public void Index_DateDescSort_OrdersByEnrollmentDateDescending()
        {
            _context.Students.AddRange(
                new Student { LastName = "A", FirstMidName = "A", EnrollmentDate = new DateTime(2020, 1, 1) },
                new Student { LastName = "B", FirstMidName = "B", EnrollmentDate = new DateTime(2022, 1, 1) }
            );
            _context.SaveChanges();

            var result = _controller.Index("date_desc", null, null, null);

            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsAssignableFrom<PaginatedList<Student>>(viewResult.Model);
            Assert.Equal(new DateTime(2022, 1, 1), model[0].EnrollmentDate);
        }

        [Fact]
        public void Index_SearchString_FiltersResults()
        {
            _context.Students.AddRange(
                new Student { LastName = "Alexander", FirstMidName = "Carson", EnrollmentDate = DateTime.Today },
                new Student { LastName = "Smith", FirstMidName = "John", EnrollmentDate = DateTime.Today }
            );
            _context.SaveChanges();

            var result = _controller.Index(null, null, "Alex", null);

            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsAssignableFrom<PaginatedList<Student>>(viewResult.Model);
            Assert.Single(model);
            Assert.Equal("Alexander", model[0].LastName);
        }

        [Fact]
        public void Index_SearchByFirstName_FiltersResults()
        {
            _context.Students.AddRange(
                new Student { LastName = "Smith", FirstMidName = "Carson", EnrollmentDate = DateTime.Today },
                new Student { LastName = "Jones", FirstMidName = "John", EnrollmentDate = DateTime.Today }
            );
            _context.SaveChanges();

            var result = _controller.Index(null, null, "Carson", null);

            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsAssignableFrom<PaginatedList<Student>>(viewResult.Model);
            Assert.Single(model);
            Assert.Equal("Smith", model[0].LastName);
        }

        [Fact]
        public void Index_SearchString_ResetsPageTo1()
        {
            // When searchString is provided (non-null), page should be set to 1
            _context.Students.Add(new Student { LastName = "Test", FirstMidName = "A", EnrollmentDate = DateTime.Today });
            _context.SaveChanges();

            var result = _controller.Index(null, null, "Test", 5);

            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsAssignableFrom<PaginatedList<Student>>(viewResult.Model);
            Assert.Equal(1, model.PageIndex);
        }

        [Fact]
        public void Index_NullSearch_UsesCurrentFilter()
        {
            _context.Students.AddRange(
                new Student { LastName = "Alexander", FirstMidName = "A", EnrollmentDate = DateTime.Today },
                new Student { LastName = "Smith", FirstMidName = "B", EnrollmentDate = DateTime.Today }
            );
            _context.SaveChanges();

            var result = _controller.Index(null, "Alexander", null, null);

            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsAssignableFrom<PaginatedList<Student>>(viewResult.Model);
            Assert.Single(model);
        }

        [Fact]
        public void Index_Pagination_ReturnsCorrectPage()
        {
            // Add 15 students
            for (int i = 0; i < 15; i++)
            {
                _context.Students.Add(new Student
                {
                    LastName = $"Student{i:D2}",
                    FirstMidName = "Test",
                    EnrollmentDate = DateTime.Today
                });
            }
            _context.SaveChanges();

            var result = _controller.Index(null, null, null, 2);

            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsAssignableFrom<PaginatedList<Student>>(viewResult.Model);
            Assert.Equal(2, model.PageIndex);
            Assert.Equal(5, model.Count); // Second page of 15 items, pageSize=10
        }

        [Fact]
        public void Index_SetsViewBagSortParameters()
        {
            var result = _controller.Index(null, null, null, null);

            Assert.Equal("name_desc", _controller.ViewBag.NameSortParm);
            Assert.Equal("Date", _controller.ViewBag.DateSortParm);
        }

        [Fact]
        public void Index_WithNameDescSort_SetsNameSortParmToEmpty()
        {
            var result = _controller.Index("name_desc", null, null, null);

            Assert.Equal("", _controller.ViewBag.NameSortParm);
        }

        [Fact]
        public void Index_WithDateSort_SetsDateSortParmToDateDesc()
        {
            var result = _controller.Index("Date", null, null, null);

            Assert.Equal("date_desc", _controller.ViewBag.DateSortParm);
        }

        #endregion

        #region Details

        [Fact]
        public void Details_NullId_ReturnsBadRequest()
        {
            var result = _controller.Details(null);
            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, statusResult.StatusCode);
        }

        [Fact]
        public void Details_ValidId_ReturnsStudentWithEnrollments()
        {
            var dept = new Department { Name = "Test", Budget = 1000, StartDate = DateTime.Today };
            _context.Departments.Add(dept);
            _context.SaveChanges();

            var course = new Course { CourseID = 100, Title = "Test Course", Credits = 3, DepartmentID = dept.DepartmentID };
            _context.Courses.Add(course);

            var student = new Student
            {
                LastName = "Test",
                FirstMidName = "Student",
                EnrollmentDate = DateTime.Today,
                Enrollments = new List<Enrollment>()
            };
            _context.Students.Add(student);
            _context.SaveChanges();

            _context.Enrollments.Add(new Enrollment { StudentID = student.ID, CourseID = 100, Grade = Grade.A });
            _context.SaveChanges();

            var result = _controller.Details(student.ID);

            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsType<Student>(viewResult.Model);
            Assert.Equal("Test", model.LastName);
            Assert.NotNull(model.Enrollments);
        }

        #endregion

        #region Create GET

        [Fact]
        public void Create_GET_ReturnsViewWithStudentHavingTodayDate()
        {
            var result = _controller.Create();

            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsType<Student>(viewResult.Model);
            Assert.Equal(DateTime.Today, model.EnrollmentDate);
        }

        #endregion

        #region Create POST

        [Fact]
        public void Create_POST_ValidModel_SavesAndRedirects()
        {
            var student = new Student
            {
                LastName = "New",
                FirstMidName = "Student",
                EnrollmentDate = new DateTime(2023, 9, 1)
            };

            var result = _controller.Create(student);

            var redirect = Assert.IsType<RedirectToActionResult>(result);
            Assert.Equal("Index", redirect.ActionName);
            Assert.Single(_context.Students);
        }

        [Fact]
        public void Create_POST_MinValueDate_AddsModelError()
        {
            var student = new Student
            {
                LastName = "New",
                FirstMidName = "Student",
                EnrollmentDate = DateTime.MinValue
            };

            var result = _controller.Create(student);

            var viewResult = Assert.IsType<ViewResult>(result);
            Assert.False(_controller.ModelState.IsValid);
            Assert.True(_controller.ModelState.ContainsKey("EnrollmentDate"));
        }

        [Fact]
        public void Create_POST_DateOutOfRange_AddsModelError()
        {
            var student = new Student
            {
                LastName = "New",
                FirstMidName = "Student",
                EnrollmentDate = new DateTime(1000, 1, 1)
            };

            var result = _controller.Create(student);

            var viewResult = Assert.IsType<ViewResult>(result);
            Assert.True(_controller.ModelState.ContainsKey("EnrollmentDate"));
        }

        [Fact]
        public void Create_POST_InvalidModelState_ReturnsView()
        {
            _controller.ModelState.AddModelError("LastName", "Required");
            var student = new Student
            {
                FirstMidName = "Student",
                EnrollmentDate = new DateTime(2023, 9, 1)
            };

            var result = _controller.Create(student);

            Assert.IsType<ViewResult>(result);
        }

        #endregion

        #region Edit GET

        [Fact]
        public void Edit_GET_NullId_ReturnsBadRequest()
        {
            var result = _controller.Edit((int?)null);
            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, statusResult.StatusCode);
        }

        [Fact]
        public void Edit_GET_NotFound_ReturnsNotFound()
        {
            var result = _controller.Edit(999);
            Assert.IsType<NotFoundResult>(result);
        }

        [Fact]
        public void Edit_GET_ValidId_ReturnsViewWithStudent()
        {
            var student = new Student { LastName = "Test", FirstMidName = "Student", EnrollmentDate = DateTime.Today };
            _context.Students.Add(student);
            _context.SaveChanges();

            var result = _controller.Edit(student.ID);

            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsType<Student>(viewResult.Model);
            Assert.Equal("Test", model.LastName);
        }

        #endregion

        #region Edit POST

        [Fact]
        public void Edit_POST_ValidModel_UpdatesAndRedirects()
        {
