namespace ContosoUniversity.Tests.Controllers
{
    public class NotificationsControllerTests : IDisposable
    {
        private readonly SchoolContext _context;
        private readonly NotificationsController _controller;
        private readonly NotificationService _notificationService;

        public NotificationsControllerTests()
        {
            TestHelper.DrainNotificationQueue();
            _context = TestHelper.CreateInMemoryContext();
            _controller = new NotificationsController(_context);
            _notificationService = new NotificationService();
        }

        public void Dispose()
        {
            _controller.Dispose();
            _context.Dispose();
            _notificationService.Dispose();
            TestHelper.DrainNotificationQueue();
        }

        [Fact]
        public void GetNotifications_NoNotifications_ReturnsEmptyList()
        {
            var result = _controller.GetNotifications();

            Assert.IsType<JsonResult>(result);
            var value = result.Value;
            Assert.NotNull(value);

            // Check that success is true and count is 0
            var successProp = value.GetType().GetProperty("success");
            var countProp = value.GetType().GetProperty("count");
            Assert.True((bool)successProp!.GetValue(value)!);
            Assert.Equal(0, (int)countProp!.GetValue(value)!);
        }

        [Fact]
        public void GetNotifications_WithNotifications_ReturnsNotifications()
        {
            // Enqueue some notifications via the static queue
            _notificationService.SendNotification("Student", "1", "Test Student", EntityOperation.CREATE);
            _notificationService.SendNotification("Course", "2", "Test Course", EntityOperation.UPDATE);

            var result = _controller.GetNotifications();

            Assert.IsType<JsonResult>(result);
            var value = result.Value;
            var successProp = value!.GetType().GetProperty("success");
            var countProp = value.GetType().GetProperty("count");
            var notificationsProp = value.GetType().GetProperty("notifications");

            Assert.True((bool)successProp!.GetValue(value)!);
            var count = (int)countProp!.GetValue(value)!;
            Assert.True(count >= 1); // At least some notifications should be returned
        }

        [Fact]
        public void GetNotifications_CapsAt10()
        {
            // Enqueue 15 notifications
            for (int i = 0; i < 15; i++)
            {
                _notificationService.SendNotification("Entity", i.ToString(), EntityOperation.CREATE);
            }

            var result = _controller.GetNotifications();

            var value = result.Value;
            var countProp = value!.GetType().GetProperty("count");
            var count = (int)countProp!.GetValue(value)!;
            Assert.True(count <= 10);
        }

        [Fact]
        public void MarkAsRead_ReturnsSuccess()
        {
            var result = _controller.MarkAsRead(1);

            Assert.IsType<JsonResult>(result);
            var value = result.Value;
            var successProp = value!.GetType().GetProperty("success");
            Assert.True((bool)successProp!.GetValue(value)!);
        }

        [Fact]
        public void Index_ReturnsView()
        {
            var result = _controller.Index();
            Assert.IsType<ViewResult>(result);
        }
    }
}

